package org.apache.commons.csv;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.function.Executable;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testValueOf_withValidFormat() {
        try (MockedStatic<CSVFormat.Predefined> predefinedMock = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat expectedFormat = CSVFormat.DEFAULT;
            CSVFormat.Predefined predefinedMockInstance = Mockito.mock(CSVFormat.Predefined.class);

            predefinedMock.when(() -> CSVFormat.Predefined.valueOf("DEFAULT")).thenReturn(predefinedMockInstance);
            Mockito.when(predefinedMockInstance.getFormat()).thenReturn(expectedFormat);

            CSVFormat actual = CSVFormat.valueOf("DEFAULT");
            assertSame(expectedFormat, actual);
        }
    }

    @Test
    void testValueOf_withNullFormat_throwsException() {
        assertThrows(NullPointerException.class, () -> CSVFormat.valueOf(null));
    }

    @Test
    void testValueOf_withInvalidFormat_throwsIllegalArgumentException() {
        try (MockedStatic<CSVFormat.Predefined> predefinedMock = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            predefinedMock.when(() -> CSVFormat.Predefined.valueOf("INVALID_FORMAT"))
                    .thenThrow(IllegalArgumentException.class);

            assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf("INVALID_FORMAT"));
        }
    }
}
